u_idp_action_form.execution_script:
// Create environment record
var env = new GlideRecord('u_development_environment');
env.initialize();
env.setValue('name', formData.environment_name);
env.setValue('owner', userId);
env.setValue('size', formData.environment_size);
env.setValue('region', formData.region);
env.setValue('ttl_hours', form.default_ttl_hours);
var envId = env.insert();

// Trigger provisioning workflow
var workflow = new Workflow();
workflow.startWorkflow('env_provisioning', envId);

return {
    success: true,
    resourceId: envId,
    resourceType: 'development_environment',
    message: 'Environment provisioning started'
};
